def run_real_test():
    # Clean up whitespace or line breaks from the copy-paste operation
    clean_code = REAL_POB_CODE.strip()
    
    if not clean_code or "PASTE_YOUR_COPIED_POB_CODE_HERE" in clean_code:
        print("\n[!] Action Required: You must open 'test_real_pob.py' and replace the placeholder text with your actual copied PoB string!")
        return

    print("Initializing calculation bridge...")
    bridge = KalandraPoBBridge()
    
    print("Decompressing raw byte data...")
    raw_xml = bridge.decode_pob_string(clean_code)
    
    # If the decoding returned an error dict, catch it here
    if isinstance(raw_xml, dict) and "error" in raw_xml:
        print(f"\n[Error] Decoding failed: {raw_xml['error']}")
        return
        
    print("Parsing XML schemas for character metrics...")
    parsed_results = bridge.extract_character_data(raw_xml)
    
    if "error" in parsed_results:
        print(f"\n[Error] Parsing metrics failed: {parsed_results['error']}")
        # Optionally print raw XML snippet for debugging
        print(f"Raw XML Preview: {str(raw_xml)[:300]}...")
        return
        
    print("\n=============================================")
    print("         REAL CHARACTER SHEET DECODED         ")
    print("=============================================")
    print(f" Class:          {parsed_results.get('class_name')}")
    print(f" Ascendancy:     {parsed_results.get('ascendancy_name')}")
    print(f" Character Lvl:  {parsed_results.get('level')}")
    print(f" Total DPS:      {parsed_results.get('total_dps'):,} DPS")
    print(f" Effective HP:   {parsed_results.get('ehp'):,} eHP")
    print(f" Maximum Life:   {parsed_results.get('life'):,} Life")
    print(f" Energy Shield:  {parsed_results.get('energy_shield'):,} ES")
    print("=============================================")
    print("Success! Live PoE character calculation verified flawlessly.")

if __name__ == "__main__":
    run_real_test()